const obj = { id: 1, name: 'Alice' };
const reference = obj;
reference.name = 'Bob';
console.log(obj.name);

class Person { String name; }
Person p = new Person();
Person reference = p;
reference.name = "Alice";

CREATE TABLE orders (
    id INT PRIMARY KEY,
    user_id INT,
    FOREIGN KEY (user_id) REFERENCES users(id)
);
